targets.expr:
sum(
  changes(
    sum without (uid, pod_ip) (
      kube_pod_info{namespace=~"soperator", pod="$pod", node!=""}
    )[1d:1m]
  )
)

100
* sum by (container) (
    container_memory_working_set_bytes{namespace=~"soperator", pod="$pod", container!="", container!="POD"}
  )
/ on (container)
  (
    sum by (container) (
      kube_pod_container_resource_limits{namespace=~"soperator", pod="$pod", resource="memory"}
    )
    or
    on (container)
    sum by (container) (
      container_memory_working_set_bytes{namespace=~"soperator", pod="$pod", container!="", container!="POD"} * 0
    )
    + on () group_left scalar(node_memory_MemAvailable_bytes{instance="$instance"})
  )
